import { type PropsWithChildren } from 'react';

import { DotLayerTooltip } from './DotLayerTooltip.js';
import type { DotLayerProps } from '../types/dot-layer.js';
import type { Location } from '../types/location.js';

/**
 * The `DotLayer` component renders data points on a map, accepting an array of data points
 * with required properties like latitude and longitude. It provides support
 * for various shapes, optional features like custom background for icons, rotation,
 * and tooltips, along with granular color customization and integration with
 * legends for color configuration.
 * @public
 */
export const DotLayer = <T extends Location>(
  _: PropsWithChildren<DotLayerProps<T>>,
) => null;

DotLayer.Tooltip = DotLayerTooltip;
DotLayer['displayName'] = 'DotLayerSlot';
